import json
import os
import boto3
from botocore.exceptions import ClientError

sns = boto3.client("sns")

DEFAULT_MESSAGE_TYPE = "plain"


def build_message(event):
    message_type = (event.get("notification_type") or event.get("message_type") or DEFAULT_MESSAGE_TYPE).lower()
    content = event.get("message") or event.get("content") or event.get("body") or ""
    subject = event.get("subject")
    attributes = event.get("message_attributes") or event.get("attributes") or {}

    if isinstance(content, dict):
        content = json.dumps(content)

    if message_type == "json":
        if not isinstance(content, str):
            content = json.dumps(content)
        message = json.dumps(
            {
                "default": content,
                "email": content,
                "sms": content,
                "lambda": content,
            }
        )
        message_structure = "json"
    elif message_type == "email":
        message = str(content)
        message_structure = "string"
    elif message_type == "sms":
        message = str(content)
        message_structure = "string"
        subject = None
    elif message_type == "alert":
        message = f"ALERT: {content}"
        message_structure = "string"
    else:
        message = str(content)
        message_structure = "string"

    return message, subject, attributes, message_structure


def build_message_attributes(attributes):
    sns_attributes = {}
    for key, value in attributes.items():
        if value is None:
            continue

        if isinstance(value, dict):
            data_type = value.get("DataType", "String")
            if data_type.startswith("Binary"):
                sns_attributes[key] = {
                    "DataType": data_type,
                    "BinaryValue": value.get("BinaryValue", b""),
                }
            else:
                sns_attributes[key] = {
                    "DataType": data_type,
                    "StringValue": str(value.get("StringValue", value.get("Value", ""))),
                }
            continue

        if isinstance(value, bool):
            sns_attributes[key] = {"DataType": "String", "StringValue": str(value).lower()}
        elif isinstance(value, int):
            sns_attributes[key] = {"DataType": "Number", "StringValue": str(value)}
        elif isinstance(value, float):
            sns_attributes[key] = {"DataType": "Number", "StringValue": str(value)}
        else:
            sns_attributes[key] = {"DataType": "String", "StringValue": str(value)}

    return sns_attributes


def lambda_handler(event, context):
    topic_arn = event.get("topic_arn") or event.get("TopicArn") or os.environ.get("TOPIC_ARN")
    if not topic_arn:
        return {
            "statusCode": 400,
            "body": json.dumps({"error": "Missing topic ARN"}),
        }

    message, subject, attributes, message_structure = build_message(event)
    sns_attributes = build_message_attributes(attributes)

    publish_kwargs = {
        "TopicArn": topic_arn,
        "Message": message,
    }

    if subject:
        publish_kwargs["Subject"] = str(subject)[:100]
    if sns_attributes:
        publish_kwargs["MessageAttributes"] = sns_attributes
    if message_structure == "json":
        publish_kwargs["MessageStructure"] = "json"

    try:
        response = sns.publish(**publish_kwargs)
        return {
            "statusCode": 200,
            "body": json.dumps(
                {
                    "message": "Notification published successfully",
                    "message_id": response.get("MessageId"),
                    "topic_arn": topic_arn,
                    "notification_type": event.get("notification_type") or event.get("message_type") or DEFAULT_MESSAGE_TYPE,
                }
            ),
        }
    except ClientError as e:
        return {
            "statusCode": 500,
            "body": json.dumps(
                {
                    "error": "Failed to publish notification",
                    "details": e.response.get("Error", {}),
                }
            ),
        }